class CycleGANDiscriminator(nn.Module):
    """PatchGAN 70x70 discriminator with InstanceNorm."""
    def __init__(self, nc: int = 3, ndf: int = 64):
        super().__init__()
        def block(in_ch, out_ch, norm=True):
            layers = [nn.Conv2d(in_ch, out_ch, 4, stride=2, padding=1, bias=False)]
            if norm:
                layers.append(nn.InstanceNorm2d(out_ch))
            layers.append(nn.LeakyReLU(0.2, True))
            return layers

        self.model = nn.Sequential(
            *block(nc, ndf, norm=False),          # no norm on first layer
            *block(ndf, ndf * 2),
            *block(ndf * 2, ndf * 4),
            *block(ndf * 4, ndf * 8),
            nn.Conv2d(ndf * 8, 1, 4, padding=1),  # patch-level score (no sigmoid)
        )

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.model(x)  # (B, 1, H', W') — one score per 70x70 patch

import random


class ImagePool:
    """
    Image history buffer to stabilise discriminator training.
    Prevents discriminator from over-fitting to the current generator.
    """
    def __init__(self, pool_size: int = 50):
        self.pool_size = pool_size
        self.images = []

    def query(self, images: torch.Tensor) -> torch.Tensor:
        """Return a batch of images, randomly mixing pool and current images."""
        if self.pool_size == 0:
            return images
        return_images = []
        for image in images:
            image = image.unsqueeze(0)
            if len(self.images) < self.pool_size:
                self.images.append(image)
                return_images.append(image)
            else:
                if random.random() > 0.5:
                    # Return image from pool (don't insert current)
                    idx = random.randint(0, self.pool_size - 1)
                    return_images.append(self.images[idx].clone())
                    self.images[idx] = image   # replace with current
                else:
                    return_images.append(image)
        return torch.cat(return_images, dim=0)
